eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   portfolioProjects: () => (/* binding */ portfolioProjects),\n/* harmony export */   projectFilters: () => (/* binding */ projectFilters)\n/* harmony export */ });\nconst projectFilters = [\n    {\n        value: \"all\",\n        label: \"Tous\"\n    },\n    {\n        value: \"web\",\n        label: \"Web\"\n    },\n    {\n        value: \"career\",\n        label: \"Emploi\"\n    },\n    {\n        value: \"data\",\n        label: \"Data\"\n    },\n    {\n        value: \"event\",\n        label: \"Événement\"\n    },\n    {\n        value: \"library\",\n        label: \"Bibliothèque\"\n    }\n];\nconst portfolioProjects = [\n    {\n        id: 1,\n        title: \"Mansa Digital\",\n        img: \"/images/projects/mansadigital-empereur.png\",\n        summary: \"Intégration front des pages de présentation de l'agence, création de composants Next.js réutilisables et adaptation responsive complète du site.\",\n        details: \"J'ai transformé les maquettes Figma en interfaces exploitables, harmonisé les sections clés du site et ajusté l'UI avec l'équipe pour rendre l'offre plus lisible et la prise de contact plus simple.\",\n        focusTag: \"Acquisition de leads\",\n        highlight: \"Objectif : rendre l'offre de l'agence plus lisible et plus convaincante pour transformer les visites en opportunités.\",\n        contribution: \"Mon rôle a porté sur l'intégration front, la structuration de composants réutilisables, la qualité du responsive et la livraison d'un rendu propre dans l'environnement Docker du projet.\",\n        roleHighlights: [\n            \"Transformation des maquettes Figma en pages vitrines fonctionnelles\",\n            \"Création de composants réutilisables en Next.js pour les sections marketing\",\n            \"Responsive complet sur mobile, tablette et desktop\",\n            \"Ajustements UI pour clarifier l'offre, les appels à l'action et les formulaires\",\n            \"Validation du rendu dans l'environnement Docker déjà en place\"\n        ],\n        problem: \"Une agence digitale a besoin d'une présence en ligne claire et crédible pour présenter ses services, rassurer les prospects et faciliter la prise de contact.\",\n        solution: \"J'ai participé à l'intégration d'un site vitrine moderne et responsive qui structure l'offre, valorise l'expertise de l'agence et simplifie le parcours de découverte.\",\n        mainFeatures: [\n            \"Présentation structurée des services et expertises\",\n            \"Navigation fluide avec une hiérarchie claire des contenus\",\n            \"Mise en avant des points de contact et de la proposition de valeur\",\n            \"Expérience responsive adaptée au desktop comme au mobile\"\n        ],\n        backOffice: {\n            summary: \"Le back-office permet de gérer les contenus visibles côté front sans repasser par une modification complète de l'interface.\",\n            features: [\n                \"Mise à jour des services, contenus et blocs de présentation\",\n                \"Gestion des prises de contact et des informations affichées\",\n                \"Organisation des contenus mis en avant sur le site\"\n            ]\n        },\n        backendPerspective: {\n            level: \"Intégré\",\n            summary: \"Le backend Symfony est déjà intégré pour structurer la partie serveur et alimenter correctement les contenus exploités côté front.\",\n            useCases: [\n                \"Stockage des formulaires de contact et suivi des leads\",\n                \"CRUD simple pour les études de cas, témoignages et services\",\n                \"Authentification admin pour la mise à jour du contenu\"\n            ],\n            note: \"Backend déjà intégré avec Symfony pour la logique serveur et l'évolution du site.\"\n        },\n        backendDocs: {\n            summary: \"Pour avancer côté front, je me suis appuyée sur les besoins métier et sur la structure fournie par le back pour intégrer les contenus de manière cohérente.\",\n            items: [\n                \"Compréhension des champs à afficher et de leur organisation\",\n                \"Alignement du front avec la logique de gestion des contenus\",\n                \"Prise en compte des retours liés à la structure serveur\"\n            ]\n        },\n        technologies: [\n            \"Next.js\",\n            \"Tailwind CSS\",\n            \"CSS\",\n            \"Docker\",\n            \"Git\",\n            \"Symfony\"\n        ],\n        link: \"https://mansa.digital/\",\n        buttonText: \"Découvrir\",\n        iconKey: \"code\",\n        category: \"Développement web\",\n        filterKey: \"web\",\n        featured: true,\n        showInCarousel: true\n    },\n    {\n        id: 2,\n        title: \"Mansa Talents\",\n        img: \"/images/projects/mansatalents.jpg\",\n        summary: \"J'ai travaillé côté front sur une plateforme emploi qui rend les parcours candidat et recruteur plus clairs, plus lisibles et plus simples à utiliser.\",\n        details: \"Mon intervention a porté sur l'expérience front, l'organisation des écrans et l'intégration des éléments utiles aux parcours de recherche d'emploi et de recrutement.\",\n        focusTag: \"Recrutement\",\n        highlight: \"Objectif : simplifier la recherche d'emploi et la gestion du recrutement sur une même plateforme.\",\n        contribution: \"Je me suis concentrée sur le front-end des interfaces utiles aux candidats et aux recruteurs, avec un vrai travail d'intégration, de lisibilité et de cohérence entre les parcours.\",\n        problem: \"Les candidats manquent souvent d'outils clairs pour valoriser leur profil, tandis que les recruteurs ont besoin d'un espace simple pour publier, trier et suivre les candidatures.\",\n        solution: \"La plateforme réunit les deux parcours dans une interface unique, avec des actions rapides pour créer un CV, consulter des offres et gérer le recrutement.\",\n        mainFeatures: [\n            \"Création et mise à jour de CV en ligne\",\n            \"Recherche d'offres et exploration d'entreprises\",\n            \"Espace recruteur pour publier et administrer les annonces\",\n            \"Parcours pensé pour accélérer la mise en relation\"\n        ],\n        backOffice: {\n            summary: \"Le back-office sert à administrer la plateforme côté recruteur et à piloter les contenus et données métiers affichés dans le front.\",\n            features: [\n                \"Gestion des offres d'emploi et de leur publication\",\n                \"Suivi des candidatures et des statuts de traitement\",\n                \"Administration des comptes et des rôles utilisateurs\"\n            ]\n        },\n        backendPerspective: {\n            level: \"Intégré\",\n            summary: \"Le backend Symfony est déjà intégré pour gérer les comptes, les rôles, les offres, les candidatures et le suivi des statuts exploités dans les écrans front.\",\n            useCases: [\n                \"Authentification distincte pour candidats et recruteurs\",\n                \"CRUD des profils, offres et candidatures\",\n                \"Stockage structuré des CV, pièces jointes et statuts\",\n                \"Règles d'accès selon les rôles et tableaux de suivi\"\n            ],\n            note: \"Backend déjà intégré avec Symfony pour piloter toute la logique métier recrutement.\"\n        },\n        backendDocs: {\n            summary: \"Mon travail front était lié aux informations et comportements définis côté back, en particulier pour les profils, les offres et les candidatures.\",\n            items: [\n                \"Compréhension des rôles candidat et recruteur\",\n                \"Utilisation de la structure des données pour afficher les offres et profils\",\n                \"Respect des statuts et informations remontés par le back-end\"\n            ]\n        },\n        technologies: [\n            \"Next.js\",\n            \"Tailwind CSS\",\n            \"CSS\",\n            \"Docker\",\n            \"Git\",\n            \"Symfony\"\n        ],\n        link: \"https://mansatalents.com/\",\n        buttonText: \"Découvrir\",\n        iconKey: \"briefcase\",\n        category: \"Plateforme emploi\",\n        filterKey: \"career\",\n        featured: false,\n        showInCarousel: true\n    },\n    {\n        id: 3,\n        title: \"Guinée Data\",\n        img: \"/images/projects/guineedata.png\",\n        summary: \"J'ai surtout accompagné le projet sur la partie UI/UX pour rendre la consultation des données plus claire, plus lisible et plus accessible.\",\n        details: \"Je n'ai pas porté tout le projet. Mon intervention s'est surtout concentrée sur l'expérience utilisateur, l'habillage visuel et la réflexion design autour de la présentation des données.\",\n        focusTag: \"UI/UX & Design Thinking\",\n        highlight: \"Ma contribution a surtout porté sur l'expérience visuelle, la clarté de lecture et la réflexion design autour des parcours, pas sur l'ensemble de la plateforme.\",\n        contribution: \"J'ai principalement assisté sur la partie UI/UX, la hiérarchie visuelle et le design thinking appliqué aux parcours de lecture et de consultation, en accompagnement du projet plutôt qu'en prise en charge complète.\",\n        problem: \"Une plateforme de données doit rendre des informations parfois denses plus lisibles pour faciliter leur consultation et leur compréhension.\",\n        solution: \"J'ai contribué à améliorer la clarté de l'interface, la hiérarchie visuelle et l'expérience de lecture afin de rendre les données plus accessibles et plus simples à parcourir.\",\n        mainFeatures: [\n            \"Amélioration de la lisibilité des écrans de consultation\",\n            \"Travail sur la hiérarchie visuelle et l'organisation des blocs\",\n            \"Réflexion design thinking autour des parcours utilisateurs\",\n            \"Support UI/UX pour une interface plus claire et plus accessible\"\n        ],\n        backOffice: {\n            summary: \"Sur la partie back-office, mon regard a surtout porté sur l'expérience utilisateur, l'organisation des informations et la clarté des écrans de gestion.\",\n            features: [\n                \"Réflexion UI/UX sur l'organisation des informations administrées\",\n                \"Travail sur la lisibilité des contenus avant affichage côté interface\",\n                \"Approche design thinking pour clarifier certains parcours de gestion\"\n            ]\n        },\n        backendPerspective: {\n            level: \"Support\",\n            summary: \"Le backend existait déjà pour alimenter la plateforme en données. Mon travail était surtout lié à la façon de les présenter côté front.\",\n            useCases: [\n                \"Compréhension des données à afficher dans l'interface\",\n                \"Prise en compte de la structure des contenus fournis par le back\",\n                \"Adaptation de l'UI aux informations réellement disponibles\"\n            ],\n            note: \"Contribution surtout UI/UX et front, avec appui sur l'existant côté back-end.\"\n        },\n        stackTitle: \"Approche et outils\",\n        technologies: [\n            \"UI/UX\",\n            \"Design Thinking\",\n            \"Hiérarchie visuelle\",\n            \"Parcours utilisateur\",\n            \"Architecture de l'information\"\n        ],\n        link: \"https://guineedata.org/\",\n        buttonText: \"Explorer\",\n        iconKey: \"database\",\n        category: \"Plateforme data\",\n        filterKey: \"data\",\n        featured: false,\n        showInCarousel: true\n    },\n    {\n        id: 4,\n        title: \"Billet Facile\",\n        img: \"/images/projects/billetfacile-official.png\",\n        summary: \"Intégration front des écrans de billetterie et d'événement, avec une interface pensée pour des actions rapides côté organisateur comme côté participant.\",\n        details: \"J'ai travaillé sur les parcours de création d'événements, de réservation et de suivi en soignant la clarté des actions, la restitution des statuts et l'adaptation responsive sur mobile.\",\n        focusTag: \"Événementiel\",\n        highlight: \"Objectif : centraliser la création d'événements, la billetterie et la gestion des participations dans une interface simple.\",\n        contribution: \"J'ai intégré des interfaces front réutilisables pour la billetterie, aligné les écrans avec les données fournies par le back Symfony et validé le rendu dans le workflow Git/Docker du projet.\",\n        roleHighlights: [\n            \"Intégration des écrans organisateur et participant pour la billetterie\",\n            \"Création de composants réutilisables pour cartes d'événement, billets et formulaires\",\n            \"Affichage clair des statuts de réservation et des informations utiles en interface\",\n            \"Responsive mobile complet pour la consultation et l'achat de billets\",\n            \"Travail aligné avec le back Symfony et le workflow Git/Docker du projet\"\n        ],\n        problem: \"La gestion manuelle des billets, invitations et participations génère des frictions, des erreurs et un manque de visibilité pour les organisateurs.\",\n        solution: \"L'application centralise la création d'événements et la gestion des billets afin d'offrir un parcours plus fluide, plus rapide et plus fiable.\",\n        mainFeatures: [\n            \"Création et gestion de billets d'événements\",\n            \"Partage d'invitations et de cagnottes\",\n            \"Suivi des participants et de la diffusion\",\n            \"Interface pensée pour des actions rapides et claires\"\n        ],\n        backOffice: {\n            summary: \"Le back-office permet aux organisateurs d'administrer les événements et les informations visibles dans les interfaces front.\",\n            features: [\n                \"Gestion des événements, billets et paramètres associés\",\n                \"Suivi des participants et des réservations\",\n                \"Administration des comptes organisateurs et des informations métier\"\n            ]\n        },\n        backendPerspective: {\n            level: \"Intégré\",\n            summary: \"Le backend Symfony est déjà intégré pour gérer les événements, les billets, les utilisateurs et l'état des réservations exploités côté front.\",\n            useCases: [\n                \"CRUD des événements, billets et organisateurs\",\n                \"Stockage des participants et statut des réservations\",\n                \"Authentification organisateur et participant\",\n                \"Synchronisation des réservations et historique des actions\"\n            ],\n            note: \"Backend déjà intégré avec Symfony pour la gestion métier de la billetterie.\"\n        },\n        backendDocs: {\n            summary: \"Pour avancer sur le front, je me suis appuyée sur les besoins fonctionnels et sur les informations exposées par le back autour des événements et des réservations.\",\n            items: [\n                \"Compréhension des données liées aux billets et événements\",\n                \"Prise en compte des statuts de réservation dans l'interface\",\n                \"Alignement du front avec les parcours organisateur et participant\"\n            ]\n        },\n        technologies: [\n            \"Next.js\",\n            \"Tailwind CSS\",\n            \"CSS\",\n            \"Docker\",\n            \"Git\",\n            \"Symfony\"\n        ],\n        link: \"https://billetfacile.com/\",\n        buttonText: \"Visiter le site\",\n        iconKey: \"ticket\",\n        category: \"Gestion d'événements\",\n        filterKey: \"event\",\n        featured: false,\n        showInCarousel: true\n    },\n    {\n        id: 5,\n        title: \"AfriBook\",\n        summary: \"Plateforme culturelle pensée pour rendre la littérature africaine francophone plus accessible, plus visible et plus vivante.\",\n        details: \"Le projet démarre avec un focus sur la Guinée et l'Afrique de l'Ouest, avec l'ambition de réunir lecteurs, auteurs et passionnés de culture dans un même espace numérique et communautaire.\",\n        focusTag: \"Culture & communauté\",\n        highlight: \"Le MVP vise à centraliser la découverte de livres africains, les profils d'auteurs et les échanges autour de la lecture dans une expérience simple et engageante.\",\n        problem: \"Les œuvres d'auteurs africains restent peu visibles, dispersées et difficiles à découvrir, tandis que les lecteurs disposent de peu d'espaces pour échanger et construire une communauté autour de la lecture.\",\n        solution: \"AfriBook réunit dans une même plateforme la découverte de livres, la valorisation des auteurs et des formats communautaires comme les Book Clubs pour créer un vrai point d'entrée culturel.\",\n        targetAudience: [\n            \"Lecteurs passionnés de 18 à 45 ans, notamment en Guinée\",\n            \"Auteurs africains francophones en recherche de visibilité\",\n            \"Relais culturels capables d'amplifier naturellement le projet\"\n        ],\n        mainFeatures: [\n            \"Page d'accueil orientée découverte\",\n            \"Filtrage des livres par auteur, pays ou thématique\",\n            \"Présentation claire des livres et des auteurs\",\n            \"Avis, commentaires et vues pour engager la communauté\",\n            \"Page dédiée au Book Club et aux rencontres littéraires\"\n        ],\n        stackTitle: \"Cadrage & design\",\n        technologies: [\n            \"Figma\",\n            \"UI/UX\",\n            \"Design Thinking\",\n            \"Cadrage MVP\",\n            \"Architecture de contenu\"\n        ],\n        link: \"\",\n        buttonText: \"Voir le projet\",\n        iconKey: \"book\",\n        category: \"Bibliothèque numérique\",\n        filterKey: \"library\",\n        featured: false,\n        showInCarousel: false\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/data/projects.js\n");

